import logo from './logo.svg';
import './App.css';
import ReactS3Client from 'react-aws-s3-typescript';
import { s3Config } from './.s3Config.ts';
import { useEffect , useState, Component } from 'react';

import "react-responsive-carousel/lib/styles/carousel.min.css"; // requires a loader
import { Carousel } from 'react-responsive-carousel';

function App() {
  const [width, setWidth] = useState(window.innerWidth);

  
  
  
  const [images , setImages] = useState([
    {'American-Robin':[]},
    {'Barn-Swallow':[]},
    {'Blue-Jay':[]},
    {'Eastern-Grey-Squirrel':[]},
    {'Ebony-Jewelwing':[]},
    {'Eristalis-Transversa':[]},
    {'Great-Blue-Heron':[]},
    {'House-Sparrow':[]},
    {'Mallard-':[]},
    {'Northern-Flicker':[]},
    {'Red-Bellied-Woodpecker':[]},
    {'Red-Winged-Blackbird':[]}
  ]);

 const [imageKeyList , setImageKeyList] = useState([
    'American-Robin',
    'Barn-Swallow',
    'Blue-Jay',
    'Eastern-Grey-Squirrel',
    'Ebony-Jewelwing',
    'Eristalis-Transversa',
    'Great-Blue-Heron',
    'House-Sparrow',
    'Mallard-',
    'Northern-Flicker',
    'Red-Bellied-Woodpecker',
    'Red-Winged-Blackbird'
  ])

  const [fileListObject , setFileListObject] = useState([])
/* AWS S3 Client */
/* listFiles.ts */
const isMobile = width <= 768;
function handleWindowSizeChange() {
  setWidth(window.innerWidth);
}
useEffect(() => {
  window.addEventListener('resize', handleWindowSizeChange);
  return () => {
      window.removeEventListener('resize', handleWindowSizeChange);
  }
}, []);
const listFiles = async () => {
    /* Import s3 config object and call the constrcutor */
    const s3 = new ReactS3Client(s3Config);

    try {
        const fileList = await s3.listFiles();

        console.log(fileList.data.Contents);
        setFileListObject(fileList.data.Contents)
        /*
        * {
        *   Response: {
        *     message: "Objects listed succesfully",
        *     data: {                   // List of Objects
        *       ...                     // Meta data
        *       Contents: []            // Array of objects in the bucket
        *     }
        *   }
        * }
        */
    } catch (exception) {
        console.log(exception);
        /* handle the exception */
    }
}
    useEffect(() => {
      listFiles();
    }, []);
    /* End of listFiles.ts */

    const PicComponent = (urlPath, species) => {
      let fullURL = process.env.REACT_APP_CLOUD_LINK + urlPath
      return(
        <div key={urlPath}>
          <img src={fullURL} width={"80vw"}/>
          {!isMobile && <p className="legend">{species}</p>}
        </div>)
      
    }
    
    const CarouselComponent = (species) => { 

      return (
        <div style={{key:{species}, padding:'4vw'}}>

          <Carousel
            emulateTouch={!!isMobile}
            showIndicators={!isMobile}
            showThumbs={!!isMobile}
            >

            {fileListObject.length >0
              && fileListObject.slice(1).filter((keyValPair) => keyValPair.Key.includes(species)).map((obj) =>{
               // console.log(obj)
                return (PicComponent(obj.Key, species))
            })}
          </Carousel>
        
      </div>)
    }

  return (
    <div id='CarouselParentComponent'>
      {imageKeyList 
        &&
        fileListObject.length > 0 
        &&
          imageKeyList.slice(!!isMobile ? 6 : 0).map((obj) =>{
          return (CarouselComponent(obj))
        })}
    </div>
    
  );
}

export default App;
